import{_ as s,c as n,l as e,a as t,t as l,a4 as i,o}from"./chunks/framework.CzsDe1xi.js";const f=JSON.parse('{"title":"mysqlbinlog命令使用时报错","description":"","frontmatter":{"title":"mysqlbinlog命令使用时报错"},"headers":[],"relativePath":"doc/数据库/Mysql/实战技巧/mysqlbinlog命令使用时报错.md","filePath":"packages/doc/src/数据库/Mysql/实战技巧/mysqlbinlog命令使用时报错.md","lastUpdated":1711637456000}'),r={name:"doc/数据库/Mysql/实战技巧/mysqlbinlog命令使用时报错.md"},c={id:"frontmatter-title",tabindex:"-1"},d=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),p=i(`<p>mysqlbinlog命令使用时报错 unknown variable &#39;default-character-set=utf8mb4&#39; 的解决办法.md</p><h2 id="mysqlbinlog命令使用时报错-unknown-variable-default-character-set-utf8mb4-的解决办法" tabindex="-1">mysqlbinlog命令使用时报错 unknown variable &#39;default-character-set=utf8mb4&#39; 的解决办法 <a class="header-anchor" href="#mysqlbinlog命令使用时报错-unknown-variable-default-character-set-utf8mb4-的解决办法" aria-label="Permalink to &quot;mysqlbinlog命令使用时报错 unknown variable &#39;default-character-set=utf8mb4&#39; 的解决办法&quot;">​</a></h2><p>为了支持emoji, mysql数据库的编码都改成了 utf8mb4, 由此也引发了mysqlbinlog命令行的错误. 比如执行 <strong>mysqlbinlog --help</strong>时报错如下:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysqlbinlog: [ERROR] unknown variable &#39;default-character-set=utf8mb4&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>执行其他操作, 比如查看binlog文件, 导出binlog文件到sql时:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysqlbinlog mysql-bin.000001</span></span>
<span class="line"><span>mysqlbinlog mysql-bin.000001 &gt; h:/1.sql</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>都一样会遇到错误.</p><p>解决方法有2种:</p><ol><li>在MySQL的配置 <code>my.cnf</code> 中将<code>default-character-set=utf8mb4</code> 修改为 <code>character-set-server = utf8mb4</code>，但是这需要重启MySQL服务, 比较麻烦</li><li>加参数 <code>--no-defaults</code></li></ol><p>第二种比较好, 但是注意: binlog的文件路径要写完整, 否则识别不了</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysqlbinlog --no-defaults D:/MySQL5.7.26/data/mysql-bin.000001 &gt; h:/1_bin.sql</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,11);function b(a,m,u,h,g,_){return o(),n("div",null,[e("h1",c,[t(l(a.$frontmatter.title)+" ",1),d]),p])}const v=s(r,[["render",b]]);export{f as __pageData,v as default};
